head.script:
// 전역변수
scwin.memJson;
scwin.privAdmin;
scwin.empNo;
scwin.g_sCurrDate;

dma_condition

scwin.onpageload = function() {
    scwin.initSetting();

    dma_condition.set("qryStDt", scwin.g_sCurrDate);
    dma_condition.set("qryEndDt", scwin.g_sCurrDate);
    //ed_reqEndDt.setValue(scwin.g_sCurrDate);
    acb_qryConKnd.setValue("1");
    acb_transYn.setValue("3");
    acb_rtnType.setValue("ALL");
    scwin.f_CloseYm();

};


scwin.onUdcCompleted = function() {
    scwin.initSetting();
};

scwin.initSetting = function(){
    scwin.memJson = $c.data.getMemInfo();

    scwin.privAdmin =  scwin.memJson.privAdmin ; 
    scwin.empNo = scwin.memJson.userId  ; 

    scwin.g_sCurrDate = WebSquare.date.getCurrentServerDate().substring(0, 8);
};

scwin.btn_retrieve_onclick = function (e) {

    scwin.f_Retrieve();
};

scwin.f_downExcelSheet = async function(){

    totCnt = ds_transList.getRowCount();
        var fileName  = "전표 전송내역.xlsx";
        var sheetName = "전표 전송내역"
        if( totCnt != 0){
            var cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");

            if (cfrm) {
                // cfGridToExcel(varGrNm, sheetTitle, sheetTitle+".xls", 4+8+16);	
                $c.data.downloadGridViewExcel(gr_transList, { fileName: fileName, sheetName: fileName });
            }
        } else {
            $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        }

}

//-------------------------------------------------------------------------
// 미전송건 집계 함수
//-------------------------------------------------------------------------
scwin.f_Batchjob = function(){


    sbm_batchJob.action ="/ac.fi.sap.SaveSapSlipTransListCMD.do";

    $c.sbm.execute(sbm_batchJob);

}

//-------------------------------------------------------------------------
// 오류건 삭제  함수
//-------------------------------------------------------------------------
scwin.f_DelErrData = function(){

    sbm_deleteErrData.action ="/ac.fi.sap.DeleteSapInterfaceErrDataCMD.do";

    $c.sbm.execute(sbm_deleteErrData);

}	


//-------------------------------------------------------------------------
// 관리 리포트 전송 함수
//-------------------------------------------------------------------------
scwin.f_ReportBatchjob = async function(){
    dma_condition.set("transYn", acb_transYn.getValue());
    dma_condition.set("qryStDt", ed_reqStartDt.getValue());
    dma_condition.set("qryEndDt", ed_reqEndDt.getValue());
    dma_condition.set("qryConKnd", acb_qryConKnd.getValue());
    dma_condition.set("closeYm", ed_srchCloseYm.getValue());
    dma_condition.set("rtnType", acb_rtnType.getValue());

    sbm_reportbatchJob.action ="/ac.fi.sap.SaveSapReportTransListCMD.do";

    $c.sbm.execute(sbm_reportbatchJob);

}
//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {    

    if(await $c.gus.cfIsNull(ed_reqStartDt.getValue())|| $c.gus.cfIsNull(ed_reqEndDt.getValue())){
        await $c.win.alert("조회일자는 필수 입니다.");
        return;
    }

    if( ed_reqStartDt.getValue() > ed_reqEndDt.getValue() ){
        $c.win.alert("조회일자가 날짜 형식에 맞지 않습니다.");
        return;
    }

    //조회시작일자가 더 클경우 체크
    if (!$c.gus.cfIsAfterDate(ed_reqStartDt.getValue(), ed_reqEndDt.getValue())) {
       await  $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        return;
    }   

    scwin.tr_retrieveSlipTransList();

};

scwin.tr_retrieveSlipTransList = function(){

    dma_condition.set("transYn", acb_transYn.getValue());
    dma_condition.set("qryStDt", ed_reqStartDt.getValue());
    dma_condition.set("qryEndDt", ed_reqEndDt.getValue());
    dma_condition.set("qryConKnd", acb_qryConKnd.getValue());
    dma_condition.set("closeYm", ed_srchCloseYm.getValue());
    dma_condition.set("rtnType", acb_rtnType.getValue());

    $c.sbm.execute(sbm_retrieveSlipTransList);
};

scwin.sbm_retrieveSlipTransList_submitDone = function(){
    totalRows.setValue(ds_transList.getRowCount());

    if( ds_transList.getRowCount() == 0 ){
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        ds_transList.removeAll();
    } else {
        if (ds_transList.getRowCount() > 0 ) {
        }
    }

};

//-------------------------------------------------------------------------
// 마지막 마감년월를 구한다.
//-------------------------------------------------------------------------	
scwin.f_CloseYm = function() {

    var ebcId = "ManagementProfitAndLossEBC";
    var queryId = "retrieveManagementProfitAndLossCloseYm";
    var param3 = '000';	// 회사코드

    sbm_closeYm.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd="+ebcId +
                                            "&queryId="+queryId +
                                            "&param3=" + param3;

	ds_closeYm.removeAll();

    $c.sbm.execute(sbm_closeYm);



};	

scwin.sbm_closeYm_submitDone = function(){
    ed_srchCloseYm.setValue(ds_closeYm.getCellData(0,"col1"));
}

scwin.sbm_deleteErrData_submitDone = async function(){
    await $c.win.alert(MSG_CM_INF_001);
	scwin.f_Retrieve(); 
}

scwin.sbm_reportbatchJob_submitDone = function(){
    $c.win.alert(MSG_CM_INF_001);
}

scwin.btn_batchJob_onclick = function (e) {
    scwin.f_ReportBatchjob()
};

scwin.btn_batchJob1_onclick = function (e) {
    scwin.f_DelErrData()
};

scwin.btn_batchJob2_onclick = function (e) {
    scwin.f_Batchjob();
};
